def perceive(data):
    # Map a raw dispute-intake record onto the state fields it informs.
    amount = data.get("amount", data.get("transaction_amount", 0))
    try:
        amount = int(round(float(amount)))
    except (TypeError, ValueError):
        amount = 0
    if amount < 0:
        amount = 0
    elif amount > 100000:
        amount = 100000
    return {"amount": amount}
